Here are comprehensive pytest-style unit tests for the `clamp` function:

```python
import pytest
from clamp import clamp  # adjust import to match your module name


# ---------------------------------------------------------------------------
# Happy path
# ---------------------------------------------------------------------------

class TestClampHappyPath:
    def test_value_within_range_returns_value(self):
        assert clamp(5.0, 0.0, 10.0) == 5.0

    def test_value_at_minimum_returns_minimum(self):
        assert clamp(0.0, 0.0, 10.0) == 0.0

    def test_value_at_maximum_returns_maximum(self):
        assert clamp(10.0, 0.0, 10.0) == 10.0

    def test_value_below_minimum_returns_minimum(self):
        assert clamp(-5.0, 0.0, 10.0) == 0.0

    def test_value_above_maximum_returns_maximum(self):
        assert clamp(15.0, 0.0, 10.0) == 10.0

    def test_integer_inputs_return_correct_value(self):
        assert clamp(5, 1, 10) == 5

    def test_integer_below_min_returns_min(self):
        assert clamp(0, 1, 10) == 1

    def test_integer_above_max_returns_max(self):
        assert clamp(11, 1, 10) == 10

    def test_negative_range_value_within_range(self):
        assert clamp(-5.0, -10.0, -1.0) == -5.0

    def test_negative_range_value_below_minimum(self):
        assert clamp(-15.0, -10.0, -1.0) == -10.0

    def test_negative_range_value_above_maximum(self):
        assert clamp(0.0, -10.0, -1.0) == -1.0

    def test_mixed_negative_positive_range(self):
        assert clamp(0.0, -10.0, 10.0) == 0.0

    def test_return_type_is_float_for_float_inputs(self):
        result = clamp(5.0, 0.0, 10.0)
        assert isinstance(result, float)


# ---------------------------------------------------------------------------
# Edge cases
# ---------------------------------------------------------------------------

class TestClampEdgeCases:
    def test_min_equals_max_value_equals_both(self):
        assert clamp(5.0, 5.0, 5.0) == 5.0

    def test_min_equals_max_value_below(self):
        assert clamp(3.0, 5.0, 5.0) == 5.0

    def test_min_equals_max_value_above(self):
        assert clamp(7.0, 5.0, 5.0) == 5.0

    def test_very_large_value_clamped_to_max(self):
        assert clamp(1e308, 0.0, 100.0) == 100.0

    def test_very_small_value_clamped_to_min(self):
        assert clamp(-1e308, 0.0, 100.0) == 0.0

    def test_float_infinity_above_max(self):
        assert clamp(float("inf"), 0.0, 100.0) == 100.0

    def test_float_negative_infinity_below_min(self):
        assert clamp(float("-inf"), 0.0, 100.0) == 0.0

    def test_float_infinity_as_max_allows_large_values(self):
        assert clamp(1e308, 0.0, float("inf")) == 1e308

    def test_float_negative_infinity_as_min_allows_small_values(self):
        assert clamp(-1e308, float("-inf"), 0.0)
